package serve

import (
	"bytes"
	"encoding/base64"
	"image"
	"image/color"
	"image/draw"
	"image/png"
	"net/http"
	"strings"

	"golang.org/x/image/font"
	"golang.org/x/image/font/gofont/goregular"
	"golang.org/x/image/font/opentype"
	"golang.org/x/image/math/fixed"
)

const wallpaperBase64 = ``

var wallpaperBG image.Image

func init() {
	data, err := base64.StdEncoding.DecodeString(wallpaperBase64)
	if err != nil {
		panic("decode wallpaper: " + err.Error())
	}
	img, err := png.Decode(bytes.NewReader(data))
	if err != nil {
		panic("decode wallpaper png: " + err.Error())
	}
	wallpaperBG = img
}

func GenerateIcon(title string, size int) ([]byte, error) {
	img := image.NewRGBA(image.Rect(0, 0, size, size))

	// Scale wallpaper background to fill icon
	srcBounds := wallpaperBG.Bounds()
	for y := range size {
		srcY := srcBounds.Min.Y + y*srcBounds.Dy()/size
		for x := range size {
			srcX := srcBounds.Min.X + x*srcBounds.Dx()/size
			img.Set(x, y, wallpaperBG.At(srcX, srcY))
		}
	}

	// Semi-transparent dark overlay for text readability in lower-right
	overlay := color.RGBA{0x00, 0x00, 0x00, 0x60}
	for y := size * 2 / 3; y < size; y++ {
		for x := range size {
			r0, g0, b0, a0 := img.At(x, y).RGBA()
			_, _, _, oa := overlay.RGBA()
			alpha := float64(oa) / 0xffff
			nr := uint8((float64(r0)*(1-alpha) + float64(0)*alpha) / 256)
			ng := uint8((float64(g0)*(1-alpha) + float64(0)*alpha) / 256)
			nb := uint8((float64(b0)*(1-alpha) + float64(0)*alpha) / 256)
			na := uint8(a0 >> 8)
			img.SetRGBA(x, y, color.RGBA{nr, ng, nb, na})
		}
	}

	if err := drawBottomRightText(img, title, size); err != nil {
		return nil, err
	}

	var buf bytes.Buffer
	if err := png.Encode(&buf, img); err != nil {
		return nil, err
	}
	return buf.Bytes(), nil
}

func drawBottomRightText(img *image.RGBA, label string, size int) error {
	fontSize := float64(size) * 0.13

	tt, err := opentype.Parse(goregular.TTF)
	if err != nil {
		return err
	}
	face, err := opentype.NewFace(tt, &opentype.FaceOptions{
		Size:    fontSize,
		DPI:     72,
		Hinting: font.HintingFull,
	})
	if err != nil {
		return err
	}
	defer face.Close()

	advance := font.MeasureString(face, label)
	metrics := face.Metrics()

	padding := fixed.I(size / 20)
	x := fixed.I(size) - advance - padding
	y := fixed.I(size) - padding - metrics.Descent

	d := &font.Drawer{
		Dst:  img,
		Src:  image.NewUniform(color.White),
		Face: face,
		Dot:  fixed.Point26_6{X: x, Y: y},
	}
	d.DrawString(label)
	return nil
}

func newIconHandler(enum CellEnumerator) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		name := strings.TrimPrefix(r.URL.Path, "/icons/")

		var isICO, is256 bool
		switch {
		case strings.HasSuffix(name, ".ico"):
			name = strings.TrimSuffix(name, ".ico")
			isICO = true
		case strings.HasSuffix(name, "-256.png"):
			name = strings.TrimSuffix(name, "-256.png")
			is256 = true
		case strings.HasSuffix(name, ".png"):
			name = strings.TrimSuffix(name, ".png")
		default:
			http.NotFound(w, r)
			return
		}

		if name == "" {
			http.NotFound(w, r)
			return
		}

		cells := enum.ListCells()
		var found *Cell
		for i := range cells {
			if cells[i].ID == name {
				found = &cells[i]
				break
			}
		}
		if found == nil {
			http.NotFound(w, r)
			return
		}

		switch {
		case isICO:
			pngData, err := GenerateIcon(found.Title, 256)
			if err != nil {
				http.Error(w, "icon generation failed", http.StatusInternalServerError)
				return
			}
			icoData, err := pngToICO(pngData)
			if err != nil {
				http.Error(w, "ico generation failed", http.StatusInternalServerError)
				return
			}
			w.Header().Set("Content-Type", "image/x-icon")
			w.Header().Set("Cache-Control", "public, max-age=3600")
			w.Write(icoData)

		case is256:
			data, err := GenerateIcon(found.Title, 256)
			if err != nil {
				http.Error(w, "icon generation failed", http.StatusInternalServerError)
				return
			}
			w.Header().Set("Content-Type", "image/png")
			w.Header().Set("Cache-Control", "public, max-age=3600")
			w.Write(data)

		default:
			data, err := GenerateIcon(found.Title, 32)
			if err != nil {
				http.Error(w, "icon generation failed", http.StatusInternalServerError)
				return
			}
			w.Header().Set("Content-Type", "image/png")
			w.Header().Set("Cache-Control", "public, max-age=3600")
			w.Write(data)
		}
	})
}

// pngToICO wraps a PNG in ICO container format (PNG-in-ICO, supported since Vista).
func pngToICO(pngData []byte) ([]byte, error) {
	img, err := png.Decode(bytes.NewReader(pngData))
	if err != nil {
		return nil, err
	}
	bounds := img.Bounds()
	w, h := bounds.Dx(), bounds.Dy()
	if w > 255 {
		w = 0
	}
	if h > 255 {
		h = 0
	}

	var buf bytes.Buffer
	// ICO header: reserved(2) + type=1(2) + count=1(2)
	buf.Write([]byte{0, 0, 1, 0, 1, 0})
	// Directory entry: width, height, colors=0, reserved=0
	buf.Write([]byte{byte(w), byte(h), 0, 0})
	// Color planes=1 (2 bytes)
	buf.Write([]byte{1, 0})
	// Bits per pixel=32 (2 bytes)
	buf.Write([]byte{32, 0})
	// Size of PNG data (4 bytes LE)
	sz := uint32(len(pngData))
	buf.Write([]byte{byte(sz), byte(sz >> 8), byte(sz >> 16), byte(sz >> 24)})
	// Offset to PNG data = 6 (header) + 16 (directory) = 22
	buf.Write([]byte{22, 0, 0, 0})
	// PNG data
	buf.Write(pngData)

	return buf.Bytes(), nil
}

// ensure draw import is used for semi-transparent overlay
var _ = draw.Src

const previewBase64 = ``

var previewBG image.Image

func init() {
	data, err := base64.StdEncoding.DecodeString(previewBase64)
	if err != nil {
		panic("decode preview: " + err.Error())
	}
	img, err := png.Decode(bytes.NewReader(data))
	if err != nil {
		panic("decode preview png: " + err.Error())
	}
	previewBG = img
}

func GeneratePreview(title string, width, height int) ([]byte, error) {
	img := image.NewRGBA(image.Rect(0, 0, width, height))

	srcBounds := previewBG.Bounds()
	for y := range height {
		srcY := srcBounds.Min.Y + y*srcBounds.Dy()/height
		for x := range width {
			srcX := srcBounds.Min.X + x*srcBounds.Dx()/width
			img.Set(x, y, previewBG.At(srcX, srcY))
		}
	}

	overlay := color.RGBA{0x00, 0x00, 0x00, 0x60}
	for y := height * 3 / 4; y < height; y++ {
		for x := range width {
			r0, g0, b0, a0 := img.At(x, y).RGBA()
			_, _, _, oa := overlay.RGBA()
			alpha := float64(oa) / 0xffff
			nr := uint8((float64(r0)*(1-alpha) + float64(0)*alpha) / 256)
			ng := uint8((float64(g0)*(1-alpha) + float64(0)*alpha) / 256)
			nb := uint8((float64(b0)*(1-alpha) + float64(0)*alpha) / 256)
			na := uint8(a0 >> 8)
			img.SetRGBA(x, y, color.RGBA{nr, ng, nb, na})
		}
	}

	if err := drawBottomRightText(img, title, max(width, height)); err != nil {
		return nil, err
	}

	var buf bytes.Buffer
	if err := png.Encode(&buf, img); err != nil {
		return nil, err
	}
	return buf.Bytes(), nil
}

func newPreviewHandler(enum CellEnumerator) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		name := strings.TrimPrefix(r.URL.Path, "/preview/")
		name = strings.TrimSuffix(name, ".png")
		if name == "" {
			http.NotFound(w, r)
			return
		}

		cells := enum.ListCells()
		var found *Cell
		for i := range cells {
			if cells[i].ID == name {
				found = &cells[i]
				break
			}
		}
		if found == nil {
			http.NotFound(w, r)
			return
		}

		data, err := GeneratePreview(found.Title, 500, 250)
		if err != nil {
			http.Error(w, "preview generation failed", http.StatusInternalServerError)
			return
		}

		w.Header().Set("Content-Type", "image/png")
		w.Header().Set("Cache-Control", "public, max-age=3600")
		w.Write(data)
	})
}
